if (webhookData.state_from_frontend && typeof webhookData.state_from_frontend === 'object') {
  conversationState = webhookData.state_from_frontend;
  console.log('Using state from webhook');
}
// PRIORITY 2: Fetch from database
else {
  try {
    const session_id = webhookData.session_id;
    const agent_id = webhookData.agent_name;

    const supabaseUrl = 'https://aoteeitreschwzkbpqyd.supabase.co';
    const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImFvdGVlaXRyZXNjaHd6a2JwcXlkIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc0NDEyMDAzNCwiZXhwIjoyMDU5Njk2MDM0fQ.EfXz8Rv_6yvI4MTDk5WoKSQ0E0jxoO3oWEMO-xAEtWU';

    const response = await fetch(
      `${supabaseUrl}/rest/v1/agent_conversation_state?session_id=eq.${encodeURIComponent(session_id)}&agent_id=eq.${encodeURIComponent(agent_id)}&status=eq.active&select=state`,
      {
        headers: {
          'apikey': supabaseKey,
          'Authorization': `Bearer ${supabaseKey}`
        }
      }
    );

    const stateData = await response.json();
    if (stateData && stateData.length > 0 && stateData[0].state) {
      conversationState = stateData[0].state;
      console.log('Loaded state from database');
