// Prepare data for newsletter HTML generation
const preparedData = $('Code - Prepare Data').first().json;
const aiOutput = $('AI Agent - Conversation').first().json.output;
const state = aiOutput.state;

// Extract all answers by topic
const topicDetails = state.selected_topics.map(topicCode => {
  const answers = state.answers[topicCode] || {};
  return {
    topic_code: topicCode,
    answers: answers
  };
});

return [{
  json: {
    user_id: preparedData.user_id,
    session_id: preparedData.session_id,
    request_id: preparedData.request_id,

    // Topics and answers
    selected_topics: state.selected_topics,
    topic_details: JSON.stringify(topicDetails, null, 2),
    all_answers: JSON.stringify(state.answers, null, 2),

    // Company context
    website_url: preparedData.website_url,
    website_icon: preparedData.website_icon,
    communication_tone: preparedData.communication_tone,
    knowledge_base: preparedData.knowledge_base,
    newsletter_instructions: preparedData.newsletter_instructions
  }
}];

// Clean HTML output
const items = $input.all();

return items.map(item => {
  let raw = item.json.output;

  if (!raw) {
    return { json: { error: 'No output field found' } };
  }

  // Remove markdown code blocks
  const cleaned = raw
    .replace(/^```html\s*/, '')
    .replace(/^```\s*/, '')
    .replace(/```$/, '')
    .trim();

  return {
    json: {
      Newsletter_HTML: cleaned
    }
  };
});
